effect.shader:
void main() {

    vec4 texColor = texture2DCv(inputImg.texture,(vec4(mod(acLayerNorm,vec2(1.0,1.0)),0.0,1.0)*acLayerToScreen).xy);
    float p = step(0.0,acLayerNorm.x) * step(acLayerNorm.x,1.0) * step(0.0,acLayerNorm.y) * step(acLayerNorm.y,1.0);
    //vec4 overlay = vec4(1.0,0.5,0.0,1.0) * p;
    vec4 overlay = vec4(acLayerNorm,p,1.0) * 0.5;
    gl_FragColor = overlay + texColor*(1.0-overlay.a);

}
